mapper.select:
SELECT bd.billing_detail_id AS billingDetailId, bd.item_name AS itemName, bd.quantity AS quantity, bd.unit_price AS unitPrice, bd.amount AS amount, bd.detail_status AS detailStatus, bm.fee_name AS feeName, bm.insurance_type_code AS insuranceTypeCode, bd.occurred_at AS occurredAt FROM BILLING_DETAIL bd JOIN BILLING_MASTER bm ON bd.billing_master_id = bm.billing_master_id
AND bd.detail_status = #{detailStatus}
AND bd.occurred_at >= #{from}
AND bd.occurred_at < #{to} + 1
ORDER BY bd.occurred_at
